            <polyline class="spark-line" points=""></polyline>
            <g class="spark-dots"></g>
          </svg>
        </figure>
        <figure class="spark" data-metric="builtArea">
          <figcaption><span class="spark-swatch" aria-hidden="true"></span>Built area <span class="spark-trend">↑</span></figcaption>
