    </section>
  </section>

  <!-- ─────────────────────────── SIDEBAR ─────────────────────────── -->
  <aside class="info-column" aria-label="Era information">

    <section class="era-head">
      <div class="era-head-top">
        <h2 id="era-title" class="era-title">—</h2>
        <p id="era-years" class="era-years">—</p>
      </div>

      <div class="confidence" id="confidence-badge" data-level="high" tabindex="0"
